    /**
     * Verify the HMAC-SHA256 signature of a webhook payload.
     *
     * @param string $body The raw request body (already-decompressed)
     * @param string $signature The signature from the X-Signature header
     * @param string $secret Your webhook secret (found in the Stream Dashboard)
     * @return bool true if the signature is valid, false otherwise
     */
    public static function verifySignature(string $body, string $signature, string $secret): bool
    {
        $expected = hash_hmac('sha256', $body, $secret);
        return hash_equals($signature, $expected);
    }

    /**
     * Decompress the body if it is gzip-prefixed (first two bytes 0x1F 0x8B), else
     * return it unchanged.
     *
     * Magic-byte detection is reliable for Stream payloads because Stream webhook
     * bodies are always JSON, and JSON cannot start with 0x1F.
     *
     * @throws InvalidWebhookException if the body has the gzip magic prefix but
     *         isn't a valid gzip stream
     */
    public static function gunzipPayload(string $body): string
    {
        if (\strlen($body) < 2 || \substr($body, 0, 2) !== self::GZIP_MAGIC) {
            return $body;
        }
        $result = @\gzdecode($body);
        if ($result === false) {
            throw new InvalidWebhookException('gzip decompression failed');
        }
        return $result;
    }

    /**
     * base64-decode an SQS Message Body, then gunzip if gzip-prefixed.
     *
     * Forward-compat: today the backend emits plain JSON to SQS; once compression
     * is extended to queue transports, bodies will be base64(gzip(json)). This
     * helper handles both cases via the magic-byte detection in {@see self::gunzipPayload()}.
     *
     * Note: if the input is plain JSON (not base64), strict base64 decoding will
     * fail and throw InvalidWebhookException. Callers receiving today's plain-JSON
     * SQS messages should call {@see self::parseEvent()} directly.
     *
     * @throws InvalidWebhookException
     */
    public static function decodeSqsPayload(string $messageBody): string
    {
        $decoded = \base64_decode($messageBody, true);
        if ($decoded === false) {
            throw new InvalidWebhookException('invalid base64');
        }
        return self::gunzipPayload($decoded);
    }

    /**
     * Extract the {@code Message} field from a standard AWS SNS notification envelope,
     * then base64-decode and gunzip. Envelope shape:
     *   {"Type":"Notification","Message":"<base64>","MessageId":"...","Timestamp":"...","TopicArn":"..."}
     *
     * @throws InvalidWebhookException
     */
    public static function decodeSnsPayload(string $notificationBody): string
    {
        $env = \json_decode($notificationBody, true);
        if (!\is_array($env)) {
            throw new InvalidWebhookException('invalid SNS envelope JSON');
        }
        $msg = $env['Message'] ?? null;
        if (!\is_string($msg)) {
            throw new InvalidWebhookException("SNS envelope missing 'Message' string field");
        }
        return self::decodeSqsPayload($msg);
    }

    /**
     * Parse a webhook payload and return the typed event for known discriminators
     * or {@see UnknownEvent} for well-formed-but-unknown ones.
     *
     * Distinct from {@see self::parseWebhookEvent()}: parseEvent returns an
     * UnknownEvent on unrecognized discriminators (forward-compat); parseWebhookEvent
     * throws.
     *
     * @return object the typed event class or UnknownEvent
     * @throws InvalidWebhookException for invalid JSON, missing/non-string type field,
     *         or known-type deserialization failure
     */
    public static function parseEvent(string $payload): object
    {
        if ($payload === '') {
            throw new InvalidWebhookException('payload must not be empty');
        }
        $data = \json_decode($payload, true);
        if (\json_last_error() !== \JSON_ERROR_NONE) {
            throw new InvalidWebhookException('failed to parse webhook payload: ' . \json_last_error_msg());
        }
        if (!\is_array($data)) {
            throw new InvalidWebhookException('webhook payload must be a JSON object');
        }
        $eventType = $data['type'] ?? null;
        if (!\is_string($eventType) || $eventType === '') {
            throw new InvalidWebhookException("webhook payload missing 'type' string field");
        }

        $eventClass = self::getEventClass($eventType);
        if ($eventClass === null) {
            $createdRaw = $data['created_at'] ?? null;
            $createdAt = null;
            if (\is_string($createdRaw)) {
                try {
                    $createdAt = new \DateTimeImmutable($createdRaw);
                } catch (\Throwable) {
                    $createdAt = null;
                }
            }
            return new UnknownEvent($eventType, $createdAt, $data);
        }

        try {
            return $eventClass::fromJson($data);
        } catch (\Throwable $e) {
            throw new InvalidWebhookException('failed to deserialize event: ' . $e->getMessage(), 0, $e);
        }
    }

    /**
     * HTTP composite: gunzip (if gzip-prefixed) -> verify HMAC-SHA256 -> parse.
     *
     * The signature header is X-Signature. The signature is HMAC-SHA256 of the
     * *uncompressed* JSON body, hex-encoded. Magic-byte detection means callers
     * can pass either the raw HTTP body or already-decompressed bytes; both work.
     *
     * @return object the typed event class or UnknownEvent
     * @throws InvalidWebhookException for signature mismatches as well as parse/decompression
     *         failures; distinguish modes via the exception's message substring
     */
    public static function verifyAndParseWebhook(string $body, string $signature, string $secret): object
    {
        $payload = self::gunzipPayload($body);
        if (!self::verifySignature($payload, $signature, $secret)) {
            throw new InvalidWebhookException('webhook signature mismatch');
        }
        return self::parseEvent($payload);
    }

    /**
     * SQS composite: base64-decode -> gunzip (if gzip-prefixed) -> parse.
     *
     * The backend emits no signature attribute on SQS messages today; this helper
     * therefore performs no signature verification. If a signed variant is added later,
     * it'll be a separate function rather than retrofitting this signature.
     *
     * @return object the typed event class or UnknownEvent
     * @throws InvalidWebhookException
     */
    public static function parseSqsPayload(string $messageBody): object
    {
        return self::parseEvent(self::decodeSqsPayload($messageBody));
    }

    /**
     * SNS composite: parse SNS envelope -> base64-decode -> gunzip -> parse.
     * Same no-signature posture as {@see self::parseSqsPayload()}.
     *
     * @return object the typed event class or UnknownEvent
     * @throws InvalidWebhookException
     */
    public static function parseSnsPayload(string $notificationBody): object
    {
        return self::parseEvent(self::decodeSnsPayload($notificationBody));
    }
}

// Spec §7 alias: canonical name `GetStream\Webhook` aliases the existing
// `GetStream\Generated\Webhook` for one minor-version cycle. New callers should
// use the canonical name; existing callers continue to work unchanged.
\class_alias(\GetStream\Generated\Webhook::class, 'GetStream\\Webhook');
